import json,sys
# Gather all var_call_* variables
results = {}
for k,v in globals().items():
    if k.startswith('var_call_'):
        try:
            # v may be a string path to a json file, a list/dict, or a string containing JSON
            if isinstance(v, str):
                # try to load file if path endswith .json
                if v.endswith('.json'):
                    with open(v,'r') as f:
                        data = json.load(f)
                else:
                    try:
                        data = json.loads(v)
                    except Exception:
                        # keep raw string
                        data = v
            else:
                data = v
            results[k] = data
        except Exception as e:
            results[k] = str(e)

# From results, extract any query records with symbol/up_days/down_days
records = []
for k,data in results.items():
    if isinstance(data, list) and data:
        first = data[0]
        if isinstance(first, dict) and 'symbol' in first:
            # data is list of records
            for rec in data:
                records.append(rec)

# Also check mapping file variable
mapping = None
if 'var_call_zzmUMXZsH2jlNBEHumFraywb' in results:
    mapping = results['var_call_zzmUMXZsH2jlNBEHumFraywb']

output = {'num_records': len(records), 'records_sample': records[:10], 'mapping_present': mapping is not None}
print('__RESULT__:')
print(json.dumps(output))

